document.addEventListener("DOMContentLoaded",()=>{const t=document.querySelectorAll('form[data-enhanced-post="true"]');if(0===t.length)return;const e=document.querySelector('meta[name="_csrf"]')?.getAttribute("content"),o=document.querySelector('meta[name="_csrf_header"]')?.getAttribute("content");t.forEach(t=>{t.addEventListener("submit",async n=>{n.preventDefault();const r=t.querySelector('button[type="submit"]'),a=r?.textContent;r&&(r.disabled=!0,r.textContent="Saving...");try{const n={};e&&o&&(n[o]=e);const r=await fetch(t.action,{method:(t.method||"POST").toUpperCase(),headers:n,body:new FormData(t),credentials:"same-origin",redirect:"follow"});if(!r.ok){const t=await r.text();throw new Error(t||`Request failed with status ${r.status}`)}if(r.redirected&&r.url)return void(window.location.href=r.url);window.location.reload()}catch(t){const e=t.message?.includes("<!DOCTYPE")?"The form could not be submitted.":t.message;window.showToast?window.showToast("error","Save failed",e):window.alert(e)}finally{r&&(r.disabled=!1,r.textContent=a)}})})});